export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/health") {
      return json({ ok: true, service: "gateway", ts: Date.now() });
    }

    // Gateway can orchestrate multiple internal services
    // Example: /gateway/aggregate?userId=... -> calls USERS and ORDERS
    if (url.pathname === "/gateway/aggregate") {
      const userId = url.searchParams.get("userId");
      if (!userId) return json({ ok: false, error: "Missing userId" }, 400);

      const headers = new Headers(request.headers);
      headers.set("x-edge-request-id", headers.get("x-edge-request-id") || crypto.randomUUID());
      headers.set("x-edge-gateway", "gateway");

      const [userResp, ordersResp] = await Promise.all([
        env.USERS.fetch(new URL(`/users/${encodeURIComponent(userId)}`, url.origin).toString(), {
          method: "GET",
          headers,
        }),
        env.ORDERS.fetch(new URL(`/orders/by-user/${encodeURIComponent(userId)}`, url.origin).toString(), {
          method: "GET",
          headers,
        }),
      ]);

      const [user, orders] = await Promise.all([safeJson(userResp), safeJson(ordersResp)]);

      return json({
        ok: true,
        user,
        orders,
        meta: {
          userStatus: userResp.status,
          ordersStatus: ordersResp.status,
        },
      });
    }

    // Default passthrough: /gateway/* -> 404
    return json({ ok: false, error: "Not Found", service: "gateway" }, 404);
  },
};

function json(obj, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(obj), {
    status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      ...extraHeaders,
    },
  });
}

async function safeJson(resp) {
  const ct = resp.headers.get("content-type") || "";
  if (ct.includes("application/json")) return await resp.json();
  const text = await resp.text();
  return { status: resp.status, body: text };
}


