export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/health") {
      return json({ ok: true, service: "users", ts: Date.now() });
    }

    // /users/:id
    const m = url.pathname.match(/^\/users\/([^/]+)$/);
    if (request.method === "GET" && m) {
      const id = decodeURIComponent(m[1]);
      return json({
        ok: true,
        user: {
          id,
          name: `user-${id}`,
          tier: id === "1" ? "pro" : "free",
        },
      });
    }

    // /users (POST)
    if (url.pathname === "/users" && request.method === "POST") {
      const payload = await safeJsonBody(request);
      const id = crypto.randomUUID();
      return json({ ok: true, user: { id, ...payload } }, 201);
    }

    return json({ ok: false, error: "Not Found", service: "users" }, 404);
  },
};

function json(obj, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(obj), {
    status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      ...extraHeaders,
    },
  });
}

async function safeJsonBody(request) {
  const ct = request.headers.get("content-type") || "";
  if (ct.includes("application/json")) return await request.json();
  const text = await request.text();
  try {
    return JSON.parse(text);
  } catch {
    return { raw: text };
  }
}


